#!/bin/bash
# Deploy updated business_identifier.py and ai_visibility.py to chaos_tester repo
# Fixes: HQ city lookup (multi-source), sector detection, sector-aware queries
set -e
cd ~/chaos_tester

echo "=== Deploying AI Visibility v2 (city lookup + sector detection) ==="

# Write business_identifier.py (updated with multi-source location + sector detection)
echo "Writing modules/business_identifier.py..."
base64 -d > modules/business_identifier.py << 'B64END'

B64END

echo "Writing modules/ai_visibility.py..."
base64 -d > modules/ai_visibility.py << 'B64END'

B64END

echo "Files written. Committing and deploying..."

# Git commit
git add modules/business_identifier.py modules/ai_visibility.py
git commit -m "fix: multi-source HQ city lookup + sector-aware AI queries

- Added 6 location sources: JSON-LD structured data, HTML address patterns,
  OpenCorporates API, IRS EO, secondary page scraping, RDAP/WHOIS
- Added sector detection: IRS NTEE codes, business name analysis,
  JSON-LD @type mapping, page content keyword analysis
- Replaced generic industry keywords with sector-specific query keywords
- Queries now use detected city and sector (e.g. 'best holding company in Seattle')
"

git push origin main

# Deploy to Cloud Run
echo "Deploying to Cloud Run..."
gcloud run deploy chaos-tester --source . --region us-central1 --allow-unauthenticated --project chaos-tester

echo "=== Deploy complete! ==="
echo "Test at: https://website-auditor.io"
